let {gridProps} = useGridList(
  {
    ...DOMCollectionProps,
    keyboardDelegate,
    // Only tab navigation is supported in grid layout.
    keyboardNavigationBehavior: layout === 'grid' ? 'tab' : keyboardNavigationBehavior,
    isVirtualized,
    shouldSelectOnPressUp: props.shouldSelectOnPressUp,
    disallowTypeAhead,
    focusOnEntry
  },
  filteredState,
  ref
);

useLayoutEffect(() => {
    if (collectionNode != null) {
      // When typing forward, we want to delay the setting of active descendant to not interrupt the native screen reader announcement
      // of the letter you just typed. If we recieve another focus event then we clear the queued update
      collectionNode.addEventListener('focusin', updateActiveDescendantEvent);
    }
    return () => {
      collectionNode?.removeEventListener('focusin', updateActiveDescendantEvent);
    };
  }, [collectionNode]);

for (let [type, items] of groupedByType) {
  if (NATIVE_DRAG_TYPES.has(type)) {
    // Only one item of a given type can be set on a data transfer.
    // Join all of the items together separated by newlines.
    let data = items.join('\n');
    dataTransfer.items.add(data, type);
  } else {
    // Set data to the first item so we have access to the list of types.
    dataTransfer.items.add(items[0], type);
  }
}

do {
    entries = await new Promise((resolve, reject) => {
      reader.readEntries(resolve, reject);
    });

    for (let entry of entries) {
      if (entry.isFile) {
        let file = await getEntryFile(entry as FileSystemFileEntry);
        yield createFileItem(file);
      } else if (entry.isDirectory) {
        yield createDirectoryItem(entry);
      }
    }
  } while (entries.length > 0);

if (target) {
  // if the event target is no longer in the document, ignore
  const ownerDocument = target.ownerDocument;
  if (!ownerDocument || !nodeContains(ownerDocument.documentElement, target)) {
    return false;
  }
  // If the target is within a top layer element (e.g. toasts), ignore.
  if (target.closest('[data-react-aria-top-layer]')) {
    return false;
  }
}

return {
  meterProps: {
    ...progressBarProps,
    // Use the meter role if available, but fall back to progressbar if not
    // Chrome currently falls back from meter automatically, and Firefox
    // does not support meter at all. Safari 13+ seems to support meter properly.
    // https://bugs.chromium.org/p/chromium/issues/detail?id=944542
    // https://bugzilla.mozilla.org/show_bug.cgi?id=1460378
    role: 'meter progressbar'
  },
  labelProps
};

if (wasKeyboardVisible || !visualViewport) {
  // If the keyboard was already visible, scroll the target into view immediately.
  scrollIntoView(target);
} else {
  // Otherwise, wait for the visual viewport to resize before scrolling so we can
  // measure the correct position to scroll to.
  visualViewport.addEventListener('resize', () => scrollIntoView(target), {once: true});
}

let {itemProps, isPressed} = useSelectableItem({
  selectionManager: manager,
  key,
  ref,
  isDisabled,
  // Link tabs should behave like native anchors (navigate on press up)
  // This avoids reopening beforeunload dialogs when browsers replay
  // queued pointer enter/leave events after cancellation.
  shouldSelectOnPressUp: shouldSelectOnPressUp ?? item?.props.href != null,
  linkBehavior: 'selection'
});

if (scrollDirection === 'horizontal') {
  style.overflowX = 'auto';
  style.overflowY = 'hidden';
} else if (scrollDirection === 'vertical' || contentSize.width === state.size.width) {
  // Set overflow-x: hidden if content size is equal to the width of the scroll view.
  // This prevents horizontal scrollbars from flickering during resizing due to resize observer
  // firing slower than the frame rate, which may cause an infinite re-render loop.
  style.overflowY = 'auto';
  style.overflowX = 'hidden';
} else {
  style.overflow = 'auto';
}

let increment = () => {
  let newValue = addColorValue(parsedValue, step);
  // if we've arrived at the same value that was previously in the state, the
  // input value should be updated to match
  // ex type 4, press increment, highlight the number in the input, type 4 again, press increment
  // you'd be at 5, then incrementing to 5 again, so no re-render would happen and 4 would be left in the input
  if (newValue === colorValue) {
    setInputValue(newValue.toString('hex'));
  }
  safelySetColorValue(newValue);
  validation.commitValidation();
};

let decrement = () => {
  let newValue = addColorValue(parsedValue, -step);
  // if we've arrived at the same value that was previously in the state, the
  // input value should be updated to match
  // ex type 4, press increment, highlight the number in the input, type 4 again, press increment
  // you'd be at 5, then incrementing to 5 again, so no re-render would happen and 4 would be left in the input
  if (newValue === colorValue) {
    setInputValue(newValue.toString('hex'));
  }
  safelySetColorValue(newValue);
  validation.commitValidation();
};

let sliderState = useSliderState({
  ...color.getChannelRange(channel),
  ...otherProps,
  numberFormatter,
  value: color.getChannelValue(channel),
  defaultValue: defaultColor.getChannelValue(channel),
  onChange(v) {
    setColor(color.withChannelValue(channel, v));
  },
  onChangeEnd(v) {
    // onChange will have already been called with the right value, this is just to trigger onChangeEnd
    if (props.onChangeEnd) {
      props.onChangeEnd(color.withChannelValue(channel, v));
    }
  }
});

if (props[privateValidationStateProp]) {
  let {
    realtimeValidation,
    displayValidation,
    updateValidation,
    resetValidation,
    commitValidation
  } = props[privateValidationStateProp] as FormValidationState;
  return {
    realtimeValidation,
    displayValidation,
    updateValidation,
    resetValidation,
    commitValidation
  };
}

const useValidate = useCallback<FormStore["useValidate"]>(
  (callback) => {
    callback = useEvent(callback);
    // Whenever the items change (for example, when form fields are lazily
    // rendered), we need to reset the callbacks so they always run in a
    // consistent order.
    const items = useStoreState(store, "items");
    useEffect(() => store.onValidate(callback), [items, callback]);
  },
  [store],
);

if (compareLayoutNumbers(size, minSize) < 0) {
  if (collapsible) {
    // Collapsible panels should snap closed or open only once they cross the halfway point between collapsed and min size.
    const halfwayPoint = (collapsedSize + minSize) / 2;
    if (compareLayoutNumbers(size, halfwayPoint) < 0) {
      size = collapsedSize;
    } else {
      size = minSize;
    }
  } else {
    size = minSize;
  }
}

const htmlValidator = new HtmlValidate({
  extends: ['html-validate:recommended'],
  rules: {
    // set relaxed to exclude error that id does not begin with letter
    'valid-id': ['error', { relaxed: true }],
    'no-inline-style': 'off',
    'prefer-native-element': ['error', { exclude: ['listbox', 'button', 'region'] }],
    // innerHTML normalizes attribute values
    // https://stackoverflow.com/questions/48092293/javascript-innerhtml-messing-with-html-attributes
    'attribute-boolean-style': 'off',
  },
});

await this.browser.performActions([
  {
    type: 'pointer',
    id: 'mouse',
    parameters: { pointerType: 'mouse' },
    actions: [
      { type: 'pointerMove', duration: 0, x: Math.ceil(resizerBox.left), y: Math.ceil(resizerBox.top) }, // hover on the resizer
      { type: 'pointerDown', button: 0 },
      { type: 'pause', duration: 30 }, // extra delay to allow event listeners to update
      { type: 'pointerMove', duration: 0, x: targetX, y: targetY },
      { type: 'pause', duration: 30 }, // extra delay to allow event listeners to update
      { type: 'pointerUp', button: 0 },
    ],
  },
]);

const expandGroup = useCallback(
  (group?: ButtonDropdownProps.ItemGroup) => {
    const groupIndex = group ? getItemIndex(group) : targetIndex;
    const firstChildIndex = [...groupIndex, 0];

    // move to the first child item unless in restricted mode
    setTargetIndex(isInRestrictedView ? groupIndex : firstChildIndex);
    setExpandedIndex(groupIndex);
  },
  [targetIndex, getItemIndex, isInRestrictedView]
);

const { __internalRootRef } = useBaseComponent('CollectionPreferences', {
  props: {},
  metadata: {
    ...parentMetadata,
    hasStripedRowsPreference: !!stripedRowsPreference,
    hasVisibleContentPreference: !!visibleContentPreference,
    hasContentDisplayPreference: !!contentDisplayPreference,
    hasContentDensityPreference: !!contentDensityPreference,
    hasStickyColumnsPreference: !!stickyColumnsPreference,
    hasContentDisplayColumnFiltering: !!contentDisplayPreference?.enableColumnFiltering,
    visibleContentOptionsCount: visibleContentPreference?.options?.length,
  },
});

if (position.dropInlineStart) {
  // For right-aligned dropdowns, use the actual rendered width when flexible width is enabled
  // to ensure proper alignment even when CSS constraints differ from calculated inlineSize
  const actualWidth = dropdownElement.getBoundingClientRect().width;
  dropdownElement.style.insetInlineStart = `calc(${horizontalScrollOffset + triggerRect.insetInlineEnd}px - ${actualWidth}px)`;
} else {
  dropdownElement.style.insetInlineStart = `${horizontalScrollOffset + triggerRect.insetInlineStart}px`;
}

const baseComponentProps = useBaseComponent(
  'ExpandableSection',
  {
    props: {
      disableContentPaddings: props.disableContentPaddings,
      headingTagOverride: props.headingTagOverride,
      variant,
    },
    metadata: {
      hasInstanceIdentifier: Boolean(analyticsMetadata?.instanceIdentifier),
      hasHeaderActions: Boolean(props.headerActions),
    },
  },
  analyticsMetadata
);

const handleCompositionEnd = () => {
  // Fire the callback while wasComposing is still true — this blocks the spurious
  // Enter keydown that fires synchronously after compositionend in some browsers.
  onCompositionEndRef.current?.();
  // Keep flag true briefly to catch immediate post-composition Enter events.
  requestAnimationFrame(() => {
    wasComposingRef.current = false;
  });
};

const [
    { highlightType, highlightedOption, highlightedIndex },
    {
      moveHighlightWithKeyboard,
      resetHighlightWithKeyboard,
      setHighlightedIndexWithMouse,
      highlightOptionWithKeyboard,
      highlightFirstOptionWithMouse,
      goHomeWithKeyboard,
      goEndWithKeyboard,
    },
  ] = useHighlightedOption({ options: options, isHighlightable });

return (
  <SingleTabStopNavigationProvider
    ref={navigationAPI}
    navigationActive={keyboardNavigation}
    getNextFocusTarget={gridNavigation.getNextFocusTarget}
    isElementSuppressed={gridNavigation.isElementSuppressed}
    onRegisterFocusable={gridNavigation.onRegisterFocusable}
    onUnregisterActive={gridNavigation.onUnregisterActive}
  >
    {children}
  </SingleTabStopNavigationProvider>
);

if (programContext.hasModuleScopeOptOut) {
  if (compiledFns.length > 0) {
    const error = new CompilerError();
    error.pushErrorDetail(
      new CompilerErrorDetail({
        reason:
          'Unexpected compiled functions when module scope opt-out is present',
        category: ErrorCategory.Invariant,
        loc: null,
      }),
    );
    handleError(error, programContext, null);
  }
  return;
}

for (const [, block] of fn.body.blocks) {
  mapTerminalSuccessors(block.terminal, successor => {
    CompilerError.invariant(fn.body.blocks.has(successor), {
      reason: `Terminal successor references unknown block`,
      description: `Block bb${successor} does not exist for terminal '${printTerminal(
        block.terminal,
      )}'`,
      loc: (block.terminal as any).loc ?? GeneratedSource,
    });
    return successor;
  });
}

for (const blockId of [...targetPostDominators, targetId]) {
  if (visited.has(blockId)) {
    continue;
  }
  visited.add(blockId);
  const block = fn.body.blocks.get(blockId)!;
  for (const pred of block.preds) {
    if (!targetPostDominators.has(pred)) {
      // The predecessor does not always reach this block, we found an item on the frontier!
      frontier.add(pred);
    }
  }
}

if (DEBUG) {
  for (const [, block] of ir.blocks) {
    for (const phi of block.phis) {
      CompilerError.invariant(!rewrites.has(phi.place.identifier), {
        reason: '[EliminateRedundantPhis]: rewrite not complete',
        loc: phi.place.loc,
      });
      for (const [, operand] of phi.operands) {
        CompilerError.invariant(!rewrites.has(operand.identifier), {
          reason: '[EliminateRedundantPhis]: rewrite not complete',
          loc: phi.place.loc,
        });
      }
    }
  }
}
